r"""
Example usage (PowerShell):

1) Using environment variables (default mode)
    $env:iTwinShareClientId="<your-client-id>"
    $env:iTwinShareClientSecret="<your-client-secret>"
    python .\iTwinShareUpdater.py --iTwinId "<your-itwin-id>"
    
2) Using Azure Key Vault
    python .\iTwinShareUpdater.py --iTwinId "<your-itwin-id>" --useKeyVault --keyVaultName "<your-keyvault-name>"
    
3) Using custom secret names (env vars or Key Vault secret names)
    python .\iTwinShareUpdater.py --iTwinId "<your-itwin-id>" --clientIdVarName "MyClientId" --clientSecretVarName "MyClientSecret"

4) Using a pre-fetched token from an environment variable
    $env:MyAccessToken="<your-access-token>"
    python .\iTwinShareUpdater.py --iTwinId "<your-itwin-id>" --tokenVarName "MyAccessToken"
"""

import argparse
import requests
import datetime
import os

def GetIMSToken(clientId, clientSecret):
    token_url = "https://ims.bentley.com/connect/token"
    scope = "itwin-platform"

    data = {
        "grant_type": "client_credentials",
        "client_id": clientId,
        "client_secret": clientSecret, 
        "scope": scope,
    }

    resp = requests.post(token_url, data=data, timeout=10)
    tokenResult = resp.json()
    if (resp.status_code != 200):
        errorDescription = tokenResult.get("error_description")
        error = tokenResult.get("error")
        result = f'Error fetching token from IMS. Status Code: {resp.status_code}. {errorDescription} - {error}'
        raise Exception(result)
    return tokenResult["access_token"]

def GetShares(iTwinId, token):
    url = f'https://api.bentley.com/accesscontrol/itwins/{iTwinId}/shares'
    headers = {"Authorization": f"Bearer {token}", "Accept": "application/vnd.bentley.itwin-platform.v2+json"}
    resp = requests.get(url, headers=headers)
    if (resp.status_code != 200):
        raise Exception(f'Error getting iTwin Shares - {resp.status_code}')
    shares = resp.json()
    return shares['shares']

def CreateShare(iTwinId, token, contractName):
    url = f'https://api.bentley.com/accesscontrol/itwins/{iTwinId}/shares'
    body = {
        "shareContract": contractName
    }
    headers = {"Authorization": f"Bearer {token}", "Accept": "application/vnd.bentley.itwin-platform.v2+json"}
    resp = requests.post(url, json=body, headers=headers)
    if (resp.status_code != 201):
        raise Exception(f'Error creating iTwin Share - {resp.status_code}')
    return resp.json().get('share')

def DeleteShare(iTwinId, shareId, token):
    url = f'https://api.bentley.com/accesscontrol/itwins/{iTwinId}/shares/{shareId}'
    headers = {"Authorization": f"Bearer {token}", "Accept": "application/vnd.bentley.itwin-platform.v2+json"}
    resp = requests.delete(url, headers=headers)
    if (resp.status_code != 204):
        raise Exception(f'Error deleting iTwin Share - {resp.status_code}')


def ResolveCredentials(args, parser):
    if args.useKeyVault:
        if not args.keyVaultName or not args.keyVaultName.strip():
            parser.error("--keyVaultName is required when --useKeyVault is set.")

        try:
            from azure.identity import DefaultAzureCredential
            from azure.keyvault.secrets import SecretClient
        except ImportError as exc:
            raise Exception(
                "Missing Azure SDK packages. Install with: pip install azure-identity azure-keyvault-secrets"
            ) from exc

        vault_url = f"https://{args.keyVaultName}.vault.azure.net"
        credential = DefaultAzureCredential()
        client = SecretClient(vault_url=vault_url, credential=credential)

        try:
            clientId = client.get_secret(args.clientIdVarName).value.strip()
        except Exception as exc:
            raise Exception(
                f"Failed to fetch client id secret '{args.clientIdVarName}' from key vault '{args.keyVaultName}'."
            ) from exc

        try:
            clientSecret = client.get_secret(args.clientSecretVarName).value.strip()
        except Exception as exc:
            raise Exception(
                f"Failed to fetch client secret '{args.clientSecretVarName}' from key vault '{args.keyVaultName}'."
            ) from exc

        return clientId, clientSecret

    clientId = os.getenv(args.clientIdVarName, "").strip()
    clientSecret = os.getenv(args.clientSecretVarName, "").strip()
    return clientId, clientSecret

def main():
    parser = argparse.ArgumentParser(description="Manage iTwin Shares")
    parser.add_argument("--iTwinId", required=True, help="iTwinId to create a share for")
    parser.add_argument("--contractName", default="Default", help="iTwin share contract name")
    parser.add_argument("--useKeyVault", action="store_true", help="Flag to use Azure Key Vault to fetch clientId and clientSecret")
    parser.add_argument("--keyVaultName", default="", help="Name of the keyvault to fetch variables from. 'useKeyVault' must be true")
    parser.add_argument("--clientIdVarName", default="iTwinShareClientId", help="Name of the variable the clientId is saved as. Either keyvault or environment variable")
    parser.add_argument("--clientSecretVarName", default="iTwinShareClientSecret", help="Name of the variable the clientSecret is saved as. Either keyvault or environment variable")
    parser.add_argument("--tokenVarName", default=None, help="The name of the environment variable where a token is stored if no clientId/secret are provided")

    args = parser.parse_args()

    if not args.iTwinId or not args.iTwinId.strip():
        parser.error("--iTwinId is required and cannot be empty.")

    token = None
    if args.tokenVarName:
        token = os.getenv(args.tokenVarName, "").strip()
        if not token:
            parser.error(f"Environment variable '{args.tokenVarName}' is missing or empty.")

    if not token:
        clientId, clientSecret = ResolveCredentials(args, parser)

        if not clientId:
            parser.error(f"Environment variable '{args.clientIdVarName}' is missing or empty.")

        if not clientSecret:
            parser.error(f"Environment variable '{args.clientSecretVarName}' is missing or empty.")

        token = GetIMSToken(clientId, clientSecret)

    # Get existing shares
    iTwinId = args.iTwinId
    shares = GetShares(iTwinId, token)
    shares.sort(key=lambda x: datetime.datetime.fromisoformat(x["expiration"].replace("Z", "+00:00")), reverse=True)

    # Delete oldest share if maximum exist
    if (len(shares) >= 10):
        DeleteShare(iTwinId, shares[-1]['id'], token)

    # Create new share and print shareKey
    newShare = CreateShare(iTwinId, token, args.contractName)
    print(newShare["shareKey"])


if __name__ == "__main__":
    main()
